40	BOOL copy_file(const std::wstring& src, const std::wstring& dest) {
41	  BOOL ret = CopyFile(src.c_str(), dest.c_str(), FALSE);
42	  if (!ret) {
43	    for (int i = 0; i < 10; ++i) {
44	      std::wstring old = dest + L".old." + std::to_wstring(i);
45	      if (MoveFileEx(dest.c_str(), old.c_str(), MOVEFILE_REPLACE_EXISTING)) {
46	        MoveFileEx(old.c_str(), NULL, MOVEFILE_DELAY_UNTIL_REBOOT);
47	        break;
48	      }
49	    }
50	    ret = CopyFile(src.c_str(), dest.c_str(), FALSE);
51	  }
52	  return ret;
53	}
