69	typedef BOOL(WINAPI* PISWOW64P2)(HANDLE, USHORT*, USHORT*);
70	BOOL is_arm64_machine() {
71	  PISWOW64P2 fnIsWow64Process2 = (PISWOW64P2)GetProcAddress(
72	      GetModuleHandle(_T("kernel32.dll")), "IsWow64Process2");
73	
74	  if (fnIsWow64Process2 == NULL) {
75	    return FALSE;
76	  }
77	
78	  USHORT processMachine;
79	  USHORT nativeMachine;
80	
81	  if (!fnIsWow64Process2(GetCurrentProcess(), &processMachine,
82	                         &nativeMachine)) {
83	    return FALSE;
84	  }
85	  return nativeMachine == IMAGE_FILE_MACHINE_ARM64;
86	}
