88	typedef HRESULT(WINAPI* PISWOWGMS)(USHORT, BOOL*);
89	typedef UINT(WINAPI* PGSW64DIR2)(LPWSTR, UINT, WORD);
90	INT get_wow_arm32_system_dir(LPWSTR lpBuffer, UINT uSize) {
91	  PISWOWGMS fnIsWow64GuestMachineSupported = (PISWOWGMS)GetProcAddress(
92	      GetModuleHandle(_T("kernel32.dll")), "IsWow64GuestMachineSupported");
93	  PGSW64DIR2 fnGetSystemWow64Directory2W = (PGSW64DIR2)GetProcAddress(
94	      GetModuleHandle(_T("kernelbase.dll")), "GetSystemWow64Directory2W");
95	
96	  if (fnIsWow64GuestMachineSupported == NULL ||
97	      fnGetSystemWow64Directory2W == NULL) {
98	    return 0;
99	  }
100	
101	  BOOL supported;
102	  if (fnIsWow64GuestMachineSupported(IMAGE_FILE_MACHINE_ARMNT, &supported) !=
103	      S_OK) {
104	    return 0;
105	  }
106	
107	  if (!supported) {
108	    return 0;
109	  }
110	
111	  return fnGetSystemWow64Directory2W(lpBuffer, uSize, IMAGE_FILE_MACHINE_ARMNT);
112	}
