121	int install_ime_file(std::wstring& srcPath,
122	                     const std::wstring& ext,
123	                     bool hant,
124	                     bool silent,
125	                     ime_register_func func) {
126	  WCHAR path[MAX_PATH];
127	  GetModuleFileNameW(GetModuleHandle(NULL), path, _countof(path));
128	
129	  std::wstring srcFileName = L"weasel";
130	
131	  srcFileName += ext;
132	  WCHAR drive[_MAX_DRIVE];
133	  WCHAR dir[_MAX_DIR];
134	  _wsplitpath_s(path, drive, _countof(drive), dir, _countof(dir), NULL, 0, NULL,
135	                0);
136	  srcPath = std::wstring(drive) + dir + srcFileName;
137	
138	  GetSystemDirectoryW(path, _countof(path));
139	  std::wstring destPath = std::wstring(path) + L"\\weasel" + ext;
140	
141	  int retval = 0;
142	  // 复制 .dll/.ime 到系统目录
143	  if (!copy_file(srcPath, destPath)) {
144	    MSG_NOT_SILENT_ID_CAP(silent, destPath.c_str(), IDS_STR_INSTALL_FAILED,
145	                          MB_ICONERROR | MB_OK);
146	    return 1;
147	  }
148	  retval += func(destPath, true, false, false, hant, silent);
149	  if (is_wow64()) {
150	    PVOID OldValue = NULL;
151	    // PW64DW64FR fnWow64DisableWow64FsRedirection =
152	    // (PW64DW64FR)GetProcAddress(GetModuleHandle(_T("kernel32.dll")),
153	    // "Wow64DisableWow64FsRedirection"); PW64RW64FR
154	    // fnWow64RevertWow64FsRedirection =
155	    // (PW64RW64FR)GetProcAddress(GetModuleHandle(_T("kernel32.dll")),
156	    // "Wow64RevertWow64FsRedirection");
157	    if (Wow64DisableWow64FsRedirection(&OldValue) == FALSE) {
158	      MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_ERRCANCELFSREDIRECT,
159	                            IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
160	      return 1;
161	    }
162	
163	    if (is_arm64_machine()) {
164	      WCHAR sysarm32[MAX_PATH];
165	      if (get_wow_arm32_system_dir(sysarm32, _countof(sysarm32)) > 0) {
166	        // Install the ARM32 version if ARM32 WOW is supported （lower than
167	        // Windows 11 24H2).
168	        std::wstring srcPathARM32 = srcPath;
169	        ireplace_last(srcPathARM32, ext, L"ARM" + ext);
170	
171	        std::wstring destPathARM32 = std::wstring(sysarm32) + L"\\weasel" + ext;
172	        if (!copy_file(srcPathARM32, destPathARM32)) {
173	          MSG_NOT_SILENT_ID_CAP(silent, destPathARM32.c_str(),
174	                                IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
175	          return 1;
176	        }
177	        retval += func(destPathARM32, true, true, true, hant, silent);
178	      }
179	
180	      // Then install the ARM64 (and x64) version.
181	      // On ARM64 weasel.dll(ime) is an ARM64X redirection DLL (weaselARM64X).
182	      // When loaded, it will be redirected to weaselARM64.dll(ime) on ARM64
183	      // processes, and weaselx64.dll(ime) on x64 processes. So we need a total
184	      // of three files.
185	
186	      std::wstring srcPathX64 = srcPath;
187	      std::wstring destPathX64 = destPath;
188	      ireplace_last(srcPathX64, ext, L"x64" + ext);
189	      ireplace_last(destPathX64, ext, L"x64" + ext);
190	      if (!copy_file(srcPathX64, destPathX64)) {
191	        MSG_NOT_SILENT_ID_CAP(silent, destPathX64.c_str(),
192	                              IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
193	        return 1;
194	      }
195	
196	      std::wstring srcPathARM64 = srcPath;
197	      std::wstring destPathARM64 = destPath;
198	      ireplace_last(srcPathARM64, ext, L"ARM64" + ext);
199	      ireplace_last(destPathARM64, ext, L"ARM64" + ext);
200	      if (!copy_file(srcPathARM64, destPathARM64)) {
201	        MSG_NOT_SILENT_ID_CAP(silent, destPathARM64.c_str(),
202	                              IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
203	        return 1;
204	      }
205	
206	      // Since weaselARM64X is just a redirector we don't have separate
207	      // HANS and HANT variants.
208	      srcPath = std::wstring(drive) + dir + L"weaselARM64X" + ext;
209	    } else {
210	      ireplace_last(srcPath, ext, L"x64" + ext);
211	    }
212	
213	    if (!copy_file(srcPath, destPath)) {
214	      MSG_NOT_SILENT_ID_CAP(silent, destPath.c_str(), IDS_STR_INSTALL_FAILED,
215	                            MB_ICONERROR | MB_OK);
216	      return 1;
217	    }
218	    retval += func(destPath, true, true, false, hant, silent);
219	    if (Wow64RevertWow64FsRedirection(OldValue) == FALSE) {
220	      MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_ERRRECOVERFSREDIRECT,
221	                            IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
222	      return 1;
223	    }
224	  }
225	  return retval;
226	}
