228	int uninstall_ime_file(const std::wstring& ext,
229	                       bool silent,
230	                       ime_register_func func) {
231	  int retval = 0;
232	  WCHAR path[MAX_PATH];
233	  GetSystemDirectoryW(path, _countof(path));
234	  std::wstring imePath(path);
235	  imePath += L"\\weasel" + ext;
236	  retval += func(imePath, false, false, false, false, silent);
237	  delete_file(imePath);
238	  if (is_wow64()) {
239	    retval += func(imePath, false, true, false, false, silent);
240	    PVOID OldValue = NULL;
241	    if (Wow64DisableWow64FsRedirection(&OldValue) == FALSE) {
242	      MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_ERRCANCELFSREDIRECT,
243	                            IDS_STR_UNINSTALL_FAILED, MB_ICONERROR | MB_OK);
244	      return 1;
245	    }
246	
247	    if (is_arm64_machine()) {
248	      WCHAR sysarm32[MAX_PATH];
249	      if (get_wow_arm32_system_dir(sysarm32, _countof(sysarm32)) > 0) {
250	        std::wstring imePathARM32 = std::wstring(sysarm32) + L"\\weasel" + ext;
251	        retval += func(imePathARM32, false, true, true, false, silent);
252	        delete_file(imePathARM32);
253	      }
254	
255	      std::wstring imePathX64 = imePath;
256	      ireplace_last(imePathX64, ext, L"x64" + ext);
257	      delete_file(imePathX64);
258	
259	      std::wstring imePathARM64 = imePath;
260	      ireplace_last(imePathARM64, ext, L"ARM64" + ext);
261	      delete_file(imePathARM64);
262	    }
263	
264	    delete_file(imePath);
265	    if (Wow64RevertWow64FsRedirection(OldValue) == FALSE) {
266	      MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_ERRRECOVERFSREDIRECT,
267	                            IDS_STR_UNINSTALL_FAILED, MB_ICONERROR | MB_OK);
268	      return 1;
269	    }
270	  }
271	  return retval;
272	}
