302	int register_text_service(const std::wstring& tsf_path,
303	                          bool register_ime,
304	                          bool is_wow64,
305	                          bool is_wowarm32,
306	                          bool hant,
307	                          bool silent) {
308	  using RegisterServerFunction = HRESULT(STDAPICALLTYPE*)();
309	
310	  if (!register_ime)
311	    enable_profile(FALSE, hant);
312	
313	  std::wstring params = L" \"" + tsf_path + L"\"";
314	  if (!register_ime) {
315	    params = L" /u " + params;  // unregister
316	  }
317	  // if (silent)  // always silent
318	  { params = L" /s " + params; }
319	
320	  if (!SetEnvironmentVariable(L"TEXTSERVICE_PROFILE",
321	                              hant ? L"hant" : L"hans")) {
322	    throw std::runtime_error("SetEnvironmentVariable failed");
323	  }
324	
325	  std::wstring app = L"regsvr32.exe";
326	  if (is_wowarm32) {
327	    WCHAR sysarm32[MAX_PATH];
328	    get_wow_arm32_system_dir(sysarm32, _countof(sysarm32));
329	
330	    app = std::wstring(sysarm32) + L"\\" + app;
331	  }
332	
333	  SHELLEXECUTEINFOW shExInfo = {0};
334	  shExInfo.cbSize = sizeof(shExInfo);
335	  shExInfo.fMask = SEE_MASK_NOCLOSEPROCESS;
336	  shExInfo.hwnd = 0;
337	  shExInfo.lpVerb = L"open";               // Operation to perform
338	  shExInfo.lpFile = app.c_str();           // Application to start
339	  shExInfo.lpParameters = params.c_str();  // Additional parameters
340	  shExInfo.lpDirectory = 0;
341	  shExInfo.nShow = SW_SHOW;
342	  shExInfo.hInstApp = 0;
343	  if (ShellExecuteExW(&shExInfo)) {
344	    WaitForSingleObject(shExInfo.hProcess, INFINITE);
345	    CloseHandle(shExInfo.hProcess);
346	  } else {
347	    WCHAR msg[100];
348	    CString str;
349	    str.LoadStringW(IDS_STR_ERRREGTSF);
350	    StringCchPrintfW(msg, _countof(msg), str, params.c_str());
351	    MSG_NOT_SILENT_ID_CAP(silent, msg, IDS_STR_INORUN_FAILED,
352	                          MB_ICONERROR | MB_OK);
353	    return 1;
354	  }
355	
356	  if (register_ime)
357	    enable_profile(TRUE, hant);
358	
359	  return 0;
360	}
