362	int install(bool hant, bool silent) {
363	  std::wstring ime_src_path;
364	  int retval = 0;
365	
366	  retval += install_ime_file(ime_src_path, L".dll", hant, silent,
367	                             &register_text_service);
368	
369	  // 写注册表
370	  WCHAR drive[_MAX_DRIVE];
371	  WCHAR dir[_MAX_DIR];
372	  _wsplitpath_s(ime_src_path.c_str(), drive, _countof(drive), dir,
373	                _countof(dir), NULL, 0, NULL, 0);
374	  std::wstring rootDir = std::wstring(drive) + dir;
375	  rootDir.pop_back();
376	  auto ret = SetRegKeyValue(HKEY_LOCAL_MACHINE, WEASEL_REG_KEY, L"WeaselRoot",
377	                            rootDir.c_str(), REG_SZ);
378	  if (FAILED(HRESULT_FROM_WIN32(ret))) {
379	    MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_ERRWRITEWEASELROOT,
380	                          IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
381	    return 1;
382	  }
383	
384	  const std::wstring executable = L"WeaselServer.exe";
385	  ret = SetRegKeyValue(HKEY_LOCAL_MACHINE, WEASEL_REG_KEY, L"ServerExecutable",
386	                       executable.c_str(), REG_SZ);
387	  if (FAILED(HRESULT_FROM_WIN32(ret))) {
388	    MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_ERRREGIMEWRITESVREXE,
389	                          IDS_STR_INSTALL_FAILED, MB_ICONERROR | MB_OK);
390	    return 1;
391	  }
392	
393	  // InstallLayoutOrTip
394	  // https://learn.microsoft.com/zh-cn/windows/win32/tsf/installlayoutortip
395	  // example in ref page not right with "*PTF_ INSTALLLAYOUTORTIP"
396	  // space inside should be removed
397	  HMODULE hInputDLL = LoadLibrary(TEXT("input.dll"));
398	  if (hInputDLL) {
399	    PTF_INSTALLLAYOUTORTIP pfnInstallLayoutOrTip;
400	    pfnInstallLayoutOrTip =
401	        (PTF_INSTALLLAYOUTORTIP)GetProcAddress(hInputDLL, "InstallLayoutOrTip");
402	    if (pfnInstallLayoutOrTip) {
403	      if (hant)
404	        (*pfnInstallLayoutOrTip)(PSZTITLE_HANT, 0);
405	      else
406	        (*pfnInstallLayoutOrTip)(PSZTITLE_HANS, 0);
407	    }
408	    FreeLibrary(hInputDLL);
409	  }
410	
411	  // https://learn.microsoft.com/zh-cn/windows/win32/wer/collecting-user-mode-dumps
412	  const std::wstring dmpPathW = WeaselLogPath().wstring();
413	  // DumpFolder
414	  SetRegKeyValue(HKEY_LOCAL_MACHINE, WEASEL_WER_KEY, L"DumpFolder",
415	                 dmpPathW.c_str(), REG_SZ, true);
416	  // dump type 0
417	  SetRegKeyValue(HKEY_LOCAL_MACHINE, WEASEL_WER_KEY, L"DumpType", 0, REG_DWORD,
418	                 true);
419	  // CustomDumpFlags, MiniDumpNormal
420	  SetRegKeyValue(HKEY_LOCAL_MACHINE, WEASEL_WER_KEY, L"CustomDumpFlags", 0,
421	                 REG_DWORD, true);
422	  // maximium dump count 10
423	  SetRegKeyValue(HKEY_LOCAL_MACHINE, WEASEL_WER_KEY, L"DumpCount", 10,
424	                 REG_DWORD, true);
425	
426	  if (retval)
427	    return 1;
428	
429	  MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_INSTALL_SUCCESS_INFO,
430	                        IDS_STR_INSTALL_SUCCESS_CAP,
431	                        MB_ICONINFORMATION | MB_OK);
432	  return 0;
433	}
434	
435	int uninstall(bool silent) {
436	  // 注销输入法
437	  int retval = 0;
438	
439	  const WCHAR KEY[] = L"Software\\Rime\\Weasel";
440	  HKEY hKey;
441	  LSTATUS ret = RegOpenKey(HKEY_CURRENT_USER, KEY, &hKey);
442	  if (ret == ERROR_SUCCESS) {
443	    DWORD type = 0;
444	    DWORD data = 0;
445	    DWORD len = sizeof(data);
446	    ret = RegQueryValueEx(hKey, L"Hant", NULL, &type, (LPBYTE)&data, &len);
447	    if (ret == ERROR_SUCCESS && type == REG_DWORD) {
448	      HMODULE hInputDLL = LoadLibrary(TEXT("input.dll"));
449	      if (hInputDLL) {
450	        PTF_INSTALLLAYOUTORTIP pfnInstallLayoutOrTip;
451	        pfnInstallLayoutOrTip = (PTF_INSTALLLAYOUTORTIP)GetProcAddress(
452	            hInputDLL, "InstallLayoutOrTip");
453	        if (pfnInstallLayoutOrTip) {
454	          if (data != 0)
455	            (*pfnInstallLayoutOrTip)(PSZTITLE_HANT, ILOT_UNINSTALL);
456	          else
457	            (*pfnInstallLayoutOrTip)(PSZTITLE_HANS, ILOT_UNINSTALL);
458	        }
459	        FreeLibrary(hInputDLL);
460	      }
461	    }
462	    RegCloseKey(hKey);
463	  }
464	
465	  // IMM/.ime support removed; only uninstall TSF/.dll
466	  retval += uninstall_ime_file(L".dll", silent, &register_text_service);
467	
468	  // 清除注册信息
469	  RegDeleteKey(HKEY_LOCAL_MACHINE, WEASEL_REG_KEY);
470	  RegDeleteKey(HKEY_LOCAL_MACHINE, RIME_REG_KEY);
471	
472	  // delete WER register,
473	  // "HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\Windows Error
474	  // Reporting\\LocalDumps\\WeaselServer.exe" no WOW64 redirect
475	
476	  auto flag_wow64 = is_wow64() ? KEY_WOW64_64KEY : 0;
477	  RegDeleteKeyEx(HKEY_LOCAL_MACHINE, WEASEL_WER_KEY, flag_wow64, 0);
478	  if (retval)
479	    return 1;
480	
481	  MSG_NOT_SILENT_BY_IDS(silent, IDS_STR_UNINSTALL_SUCCESS_INFO,
482	                        IDS_STR_UNINSTALL_SUCCESS_CAP,
483	                        MB_ICONINFORMATION | MB_OK);
484	  return 0;
485	}
