487	bool has_installed() {
488	  WCHAR path[MAX_PATH];
489	  GetSystemDirectory(path, _countof(path));
490	  std::wstring sysPath(path);
491	  DWORD attr = GetFileAttributesW((sysPath + L"\\weasel.dll").c_str());
492	  return (attr != INVALID_FILE_ATTRIBUTES &&
493	          !(attr & FILE_ATTRIBUTE_DIRECTORY));
494	}
